export default {
  async fetch(request, env, ctx) {
    // This worker handles user-related logic
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/api/users' && request.method === 'GET') {
      return new Response('List of users from Users Service', { status: 200 });
    } else if (path === '/api/users' && request.method === 'POST') {
      const body = await request.json();
      return new Response(`Created user: ${JSON.stringify(body)}`, { status: 201 });
    } else if (path.startsWith('/api/users/') && request.method === 'GET') {
      const userId = path.split('/').pop();
      return new Response(`Details for user ${userId} from Users Service`, { status: 200 });
    }

    return new Response('Users Service: Not Found', { status: 404 });
  },
};

